def search_google(query, max_results=5):
    """执行 Google 搜索，返回结果页面 URL 列表。"""
    url = f"https://www.google.com/search?q={quote_plus(query)}&num={max_results}"
    try:
        page = Fetcher.get(url, timeout=15, retries=1)
        status = getattr(page, "status", 0)
        if not str(status).startswith("2"):
            return []

        # 提取搜索结果链接
        result_urls = []
        if hasattr(page, "css"):
            for link in page.css("a"):
                href = link.attrib.get("href", "")
                if href and "/url?q=" in href:
                    # 提取真实 URL
                    real_url = href.split("/url?q=")[1].split("&")[0]
                    if real_url.startswith("http"):
                        parsed = urlparse(real_url)
                        domain = parsed.netloc.lower()
                        # 排除 Google 自己的链接和噪声域名
                        if "google.com" not in domain and "googleapis.com" not in domain:
                            result_urls.append(real_url)
                            if len(result_urls) >= max_results:
                                break
        return result_urls
    except Exception:
