128	function parseCsv(text) {
129	  const rows = [];
130	  let row = [];
131	  let cell = "";
132	  let inQuotes = false;
133	
134	  for (let i = 0; i < text.length; i += 1) {
135	    const char = text[i];
136	    const next = text[i + 1];
137	
138	    if (char === '"' && inQuotes && next === '"') {
139	      cell += '"';
140	      i += 1;
141	    } else if (char === '"') {
142	      inQuotes = !inQuotes;
143	    } else if (char === "," && !inQuotes) {
144	      row.push(cell);
145	      cell = "";
146	    } else if ((char === "\n" || char === "\r") && !inQuotes) {
147	      if (char === "\r" && next === "\n") i += 1;
148	      row.push(cell);
149	      if (row.some((value) => value !== "")) rows.push(row);
150	      row = [];
