430	  const contacts = getLeadContacts(lead.lead_id);
431	  if (!contacts.length) {
432	    els.contactList.innerHTML = '<div class="empty">还没有联系人记录，可在下方新增。</div>';
433	    return;
434	  }
435	
436	  els.contactList.innerHTML = contacts.map(({ contact, index }, visibleIndex) => `
437	    <article class="contact-card editable-contact">
438	      <div class="contact-title">
439	        <strong>联系人 ${visibleIndex + 1}: ${escapeHtml(contact.contact_name || "未命名联系人")}</strong>
440	        <span>${escapeHtml(contact.contact_id || "")}</span>
441	      </div>
442	      <div class="edit-grid">
443	        ${contactEditFields.map(([name, label]) => makeInput(`contact.${index}.${name}`, label, contact[name], longContactFields.has(name))).join("")}
444	      </div>
445	    </article>
446	  `).join("");
447	}
448	
449	function renderNewContactFields() {
450	  els.newContactFields.innerHTML = contactEditFields
451	    .filter(([name]) => name !== "is_primary_contact")
452	    .map(([name, label]) => makeInput(`new_contact.${name}`, label, state.newContactDraft[name], longContactFields.has(name)))
453	    .join("");
454	}
455	
456	function renderPresets() {
457	  fillPresetSelect(els.nextActionPreset, presetOptions.next_action);
458	  fillPresetSelect(els.notesPreset, presetOptions.notes);
459	  fillPresetSelect(els.enrichmentNotesPreset, presetOptions.enrichment_notes);
460	}
461	
462	function fillPresetSelect(select, options) {
463	  select.innerHTML = options.map((option) => `<option value="${escapeHtml(option)}">${escapeHtml(option)}</option>`).join("");
464	}
465	
466	function render() {
467	  const leads = filteredLeads();
468	  renderSummary(leads);
469	  renderLeadList(leads);
470	  renderEditor();
471	}
472	
473	function applyLeadEdits({ rerender = true } = {}) {
474	  const lead = state.leads.find((item) => item.lead_id === state.selectedLeadId);
475	  if (!lead) return false;
476	  let changed = false;
477	
478	  els.editFields.querySelectorAll("[data-field]").forEach((input) => {
479	    const field = input.dataset.field;
480	    const nextValue = input.value.trim();
481	    if ((lead[field] ?? "") !== nextValue) {
482	      lead[field] = nextValue;
483	      changed = true;
484	    }
485	  });
486	
487	  if (changed) {
488	    lead.last_updated = currentTimestamp();
489	    lead.change_note = appendNote(lead.change_note, editorStamp("updated lead in dashboard."));
490	  }
491	  applyContactEdits();
492	  setMessage(`已应用 ${lead.company_name || lead.lead_id} 的当前修改。导出 leads.csv / contacts.csv 后即可作为最新数据源。`);
493	  if (rerender) render();
494	  return true;
495	}
496	
497	function applyContactEdits() {
498	  els.contactList.querySelectorAll("[data-field^='contact.']").forEach((input) => {
499	    const [, indexText, field] = input.dataset.field.split(".");
500	    const contact = state.contacts[Number(indexText)];
501	    if (!contact) return;
502	    const nextValue = input.value.trim();
503	    if ((contact[field] ?? "") !== nextValue) {
504	      contact[field] = nextValue;
505	      contact.last_updated = currentTimestamp();
506	      contact.change_note = appendNote(contact.change_note, editorStamp("updated contact in dashboard."));
507	    }
508	  });
509	}
510	
511	function addContact() {
512	  const lead = state.leads.find((item) => item.lead_id === state.selectedLeadId);
513	  if (!lead) return;
514	  applyLeadEdits({ rerender: false });
515	
516	  const draft = {};
517	  els.newContactFields.querySelectorAll("[data-field]").forEach((input) => {
518	    const name = input.dataset.field.replace("new_contact.", "");
519	    draft[name] = input.value.trim();
520	  });
521	
522	  const hasAnyValue = Object.values(draft).some((value) => !isBlank(value));
523	  if (!hasAnyValue) {
524	    setMessage("新增联系人至少需要填写一项信息。", true);
525	    return;
526	  }
527	
528	  const contact = {};
529	  state.contactHeaders.forEach((header) => {
530	    contact[header] = "";
531	  });
532	
533	  Object.assign(contact, draft, {
534	    contact_id: nextContactId(),
535	    lead_id: lead.lead_id,
536	    company_name: lead.company_name,
537	    is_primary_contact: getLeadContacts(lead.lead_id).length ? "No" : "Yes",
538	    last_researched_date: currentDate(),
539	    last_updated: currentTimestamp(),
540	    change_note: editorStamp("created contact in dashboard."),
541	  });
542	
543	  state.contacts.push(contact);
544	  state.newContactDraft = {};
545	  setMessage(`已新增联系人到 ${lead.company_name || lead.lead_id}。导出 contacts.csv 后即可作为最新数据源。`);
546	  render();
547	}
548	
549	function applyPreset(field, value, mode) {
550	  const input = els.editFields.querySelector(`[data-field="${field}"]`);
551	  if (!input) return;
552	  if (mode === "replace") {
553	    input.value = value;
554	  } else if (!input.value.includes(value)) {
555	    input.value = input.value.trim() ? `${input.value.trim()} ${value}` : value;
556	  }
557	}
558	
559	function appendNote(existing, note) {
560	  const text = String(existing ?? "").trim();
561	  if (!text) return note;
562	  if (text.includes(note)) return text;
563	  return `${text} ${note}`;
564	}
565	
566	function currentDate() {
567	  return new Date().toISOString().slice(0, 10);
568	}
569	
570	function currentTimestamp() {
571	  const now = new Date();
572	  const pad = (value) => String(value).padStart(2, "0");
573	  return `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}:${pad(now.getMinutes())}`;
574	}
575	
576	function nextContactId() {
577	  const maxId = state.contacts.reduce((max, contact) => {
578	    const match = String(contact.contact_id || "").match(/CONTACT-(\d+)/);
579	    return match ? Math.max(max, Number(match[1])) : max;
580	  }, 0);
581	  return `CONTACT-${String(maxId + 1).padStart(4, "0")}`;
582	}
583	
584	function downloadCsv(filename, records, headers) {
585	  applyLeadEdits({ rerender: false });
586	  const blob = new Blob([toCsv(records, headers)], { type: "text/csv;charset=utf-8" });
587	  const url = URL.createObjectURL(blob);
588	  const link = document.createElement("a");
589	  link.href = url;
590	  link.download = filename;
591	  document.body.appendChild(link);
592	  link.click();
593	  link.remove();
594	  URL.revokeObjectURL(url);
595	  setMessage(`已导出 ${filename}。本次导出已写入编辑人、时间和修改记录。`);
596	  render();
597	}
598	
599	function readFile(input, setter) {
600	  const file = input.files?.[0];
601	  if (!file) return;
602	  const reader = new FileReader();
603	  reader.onload = () => {
604	    setter(String(reader.result || ""));
605	    setMessage(`已导入 ${file.name}。`);
606	  };
607	  reader.onerror = () => setMessage(`读取 ${file.name} 失败。`, true);
608	  reader.readAsText(file, "utf-8");
609	}
610	
611	els.loadDefaultBtn.addEventListener("click", loadDefaults);
612	els.leadsCsvInput.addEventListener("change", () => readFile(els.leadsCsvInput, setLeads));
613	els.contactsCsvInput.addEventListener("change", () => readFile(els.contactsCsvInput, setContacts));
614	els.countryFilter.addEventListener("change", render);
615	els.missingFilter.addEventListener("change", render);
616	els.searchInput.addEventListener("input", render);
617	els.resetBtn.addEventListener("click", () => {
618	  els.countryFilter.value = "";
619	  els.missingFilter.value = "";
620	  els.searchInput.value = "";
621	  render();
622	});
623	els.leadList.addEventListener("click", (event) => {
624	  const button = event.target.closest("[data-select-lead]");
625	  if (!button) return;
626	  state.selectedLeadId = button.dataset.selectLead;
627	  render();
628	});
629	els.saveEditBtn.addEventListener("click", () => applyLeadEdits());
630	els.addContactBtn.addEventListener("click", addContact);
631	els.applyNextActionPresetBtn.addEventListener("click", () => applyPreset("next_action", els.nextActionPreset.value, "replace"));
632	els.appendNotesPresetBtn.addEventListener("click", () => applyPreset("notes", els.notesPreset.value, "append"));
633	els.appendEnrichmentPresetBtn.addEventListener("click", () => applyPreset("enrichment_notes", els.enrichmentNotesPreset.value, "append"));
634	els.exportLeadsBtn.addEventListener("click", () => downloadCsv("leads.csv", state.leads, state.leadHeaders));
635	els.exportContactsBtn.addEventListener("click", () => downloadCsv("contacts.csv", state.contacts, state.contactHeaders));
636	
637	renderPresets();
638	loadDefaults();
639

